"""
mkt-context Layer — Exodus chapters 16–18
Run: python3 scripts/zc-context-exodus-16-18-fill.py

Key historical/ANE context decisions:
- Ch 16: The wilderness of Sin (Sinai Peninsula's western edge, between Elim and Sinai);
  manna's natural identification debate (tamarisk insect secretions, lichen, etc.) vs.
  the miraculous features that exceed any natural explanation (day 6 double portion,
  none on sabbath, no maggots when stored on sabbath); manna as proto-sabbath legislation
  (the sabbath rest is 'discovered' via manna before Sinai); quail (s'lav) as regular
  migratory birds in the Sinai that arrived providentially.
- Ch 17: Rephidim = last station before Sinai; Massah/Meribah as place-names encoding
  the theological verdict on the water-complaint; Amalek as Israel's first external enemy
  (Esau's grandson Gen 36:12; the Amalekites are attested in Egyptian and Akkadian sources
  as a nomadic desert people of the Negev/Sinai); the battle of Moses's arms as the first
  military theology text in the Bible.
- Ch 18: Jethro as a Midianite priest (komer/kohen); the Midianite connection to Moses
  (he spent 40 years among Midianites); Jethro's confession 'now I know that YHWH is
  greater than all gods' as the first Gentile doxology; the judicial reorganization as
  proto-Sanhedrin structure (rulers of thousands/hundreds/fifties/tens = the basis of
  Israelite legal administration through the monarchy).
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

EXODUS_CONTEXT = {
  "16": {
    "1": "<p><b>They set out from Elim, and all the congregation of the people of Israel came to the wilderness of Sin, which is between Elim and Sinai:</b> The wilderness of Sin (midbar Sin) should not be confused with the Sinai peninsula name — Sin is likely derived from the Sumero-Akkadian moon-god Sin (Nanna), whose worship was practiced at the Egyptian mining and trading outpost of Serabit el-Khadim in the Sinai. The route from Elim (12 springs, 70 palms) through the wilderness of Sin toward Sinai follows the western Sinai coastal track. The date — the fifteenth of the second month — is exactly one month after the Passover/Exodus, giving the manna miracle a precise chronological anchor.</p>",
    "2": "<p><b>And the whole congregation of the people of Israel grumbled (vayyillonu) against Moses and Aaron in the wilderness:</b> The wilderness complaint-cycle (murmuring) is a consistent structural feature of the wilderness narrative that is theologically analyzed in Ps 78, 95, 106, and 1 Cor 10:6-10. The technical verb lun (to grumble/murmur) appears most frequently in Exodus and Numbers. Ancient Near Eastern parallels for wilderness-survival complaints exist in Egyptian travel literature (the Sinuhe story, c. 1900 BCE, describes the hardships of desert travel) but the structured theological pattern of complaint-provision-ingratitude is unique to Israel's covenant relationship with YHWH.</p>",
    "3": "<p><b>'We sat by the meat pots (sirot habasar) and ate bread to the full. For you have brought us out into this wilderness to kill this whole assembly with hunger.'</b> The 'meat pots of Egypt' (sirot habasar) have become proverbial for the deceptive attractiveness of slavery's material provisions. Archaeologically, the diet of Egyptian laborers (including foreign slave-labor) is attested in ancient Egyptian administrative records: daily rations of bread, beer, vegetables, and occasional fish and meat were issued to workers on large state projects. The memory of adequate nutrition in Egypt (even in servitude) vs. the uncertainty of the wilderness is a genuine psychological tension.</p>",
    "4": "<p><b>'Behold, I am about to rain bread (lechem) from heaven for you, and the people shall go out and gather a day's portion every day, that I may test them (anassenu), whether they will walk in my law or not.'</b> The test (nassah) structure — provision given with conditions attached to reveal the people's heart — is the standard ANE framework for covenant loyalty trials. The manna is simultaneously provision and test: daily dependence built into the logistics (gather only one day's portion). The 'bread from heaven' (lechem min hashamayim) formula becomes the OT template for the eschatological messianic feast; Jesus cites it explicitly (John 6:31-35) when identifying himself as the true bread from heaven.</p>",
    "5": "<p><b>'On the sixth day, when they prepare what they bring in, it will be twice as much as they gather daily.'</b> The double portion on the sixth day is the first Sabbath instruction in the post-Exodus narrative — the Sabbath principle is introduced through the manna logistics before it is formally legislated at Sinai (ch.20). The manna narrative is the proto-legislation for the Sabbath: Israel learns the rest-pattern through food provision before the commandment is given. The double-gathering on day six (and the non-availability on day seven) is the material form of the commandment.</p>",
    "6": "<p><b>So Moses and Aaron said to all the people of Israel, 'At evening you shall know that it was YHWH who brought you out of the land of Egypt.'</b> The evening-morning structure of the provision (quail at evening, manna in the morning) mirrors the creation-week's evening-morning pattern (Gen 1). The provision is both a daily re-creation and a daily reminder of the Exodus — 'you shall know (yeda'tem) that YHWH brought you out': the manna is an epistemological event, producing covenant knowledge (da'at) through daily experience.</p>",
    "7": "<p><b>'And in the morning you shall see the glory (k'vod) of YHWH, because he has heard your grumbling against YHWH. For what are we, that you grumble against us?'</b> The glory of YHWH (kavod YHWH) appears in the cloud (v.10) as the visible manifestation of the divine presence. The logic of Moses's rebuke: grumbling against Moses and Aaron is grumbling against YHWH, because they are YHWH's agents. The delegation of divine authority creates a corresponding accountability — rejecting the representative is rejecting the principal. This principle structures all subsequent prophetic authority claims.</p>",
    "8": "<p><b>'When YHWH gives you in the evening meat to eat and in the morning bread to the full, because YHWH has heard your grumbling that you grumble against him — what are we? Your grumbling is not against us but against YHWH.'</b> The paired provision (meat/evening + bread/morning) as a direct divine response to the complaint 'we sat by the meat pots' (v.3). YHWH does not rebuke the hunger complaint per se but provides exactly what was requested while simultaneously transforming the context: the provision comes from YHWH, not Egypt. The meat pots of Egypt are replaced by quail from YHWH.</p>",
    "9": "<p><b>Then Moses said to Aaron, 'Say to the whole congregation of the people of Israel, Come near before YHWH, for he has heard your grumbling.'</b> The formal assembly (qahal) before YHWH — the congregation draws near not for punishment but for provision. The divine response to the wilderness complaint is grace, not wrath (at this stage in the wilderness journey). The pattern changes later (Num 11) when YHWH's anger is kindled by the same complaint after Sinai — the covenant context changes the moral weight of ingratitude.</p>",
    "10": "<p><b>And as soon as Aaron spoke to the whole congregation of the people of Israel, they looked toward the wilderness, and behold, the glory of YHWH appeared in the cloud:</b> The glory in the cloud (kavod YHWH b'anan) is the visible theophanic manifestation that will later settle on Sinai (24:16) and fill the tabernacle (40:34-35). The appearance of kavod is here in response to the people's complaint — the divine response to human need comes through the manifestation of divine presence. The cloud that guided Israel (13:21-22) is the same cloud in which the glory dwells.</p>",
    "11": "<p><b>And YHWH said to Moses, 'I have heard the grumbling of the people of Israel.'</b> YHWH's direct acknowledgment that he heard (shama'ti et-t'lunot) the grumbling is remarkable: the same divine hearing that responded to the cry of oppression in Egypt (2:24; 3:7) now responds to the grumbling of the wilderness. YHWH's responsiveness to Israel's needs — even their faithless complaints — is a consistent feature of the wilderness relationship that structures subsequent prophetic appeals to the Exodus tradition.</p>",
    "12": "<p><b>'At twilight you shall eat meat, and in the morning you shall be filled with bread. Then you shall know that I am YHWH your God.'</b> The da'at-YHWH formula ('you shall know that I am YHWH your God') that drove the plague narrative now structures the wilderness provision. The plagues made Egypt know YHWH by judgment; the manna makes Israel know YHWH by provision. The same epistemological purpose (knowledge of YHWH) is achieved through opposite means for opposite audiences.</p>",
    "13": "<p><b>In the evening quail (s'lav) came up and covered the camp, and in the morning dew lay around the camp:</b> S'lav = quail (Coturnix coturnix, the common quail). Quail migrate annually across the Sinai Peninsula from Africa to Europe in the spring (March-April) and return in the autumn. They migrate at night in enormous flocks and frequently land exhausted near the ground, making them easy to catch in large numbers. The quail provision is seasonally and geographically plausible in the Sinai setting — but the timing and location of the provision at the precise moment of Israel's need is the miraculous element. The Sinai quail-migration tradition is attested in ancient Egyptian texts.</p>",
    "14": "<p><b>And when the dew had gone up, there was on the face of the wilderness a fine, flake-like thing, fine as frost on the ground:</b> The manna's physical description — fine (daq), flake-like (m'chuspas), like hoarfrost — has invited comparison with natural substances. The leading natural candidate is the secretion of the tamarisk scale insect (Trabutina mannipara), which exudes a honey-like substance on tamarisk trees in the Sinai that appears as small, white, crystalline flakes in the morning; Bedouin collect and use it today. However, the manna's miraculous features (double on day six, no maggots on sabbath, none on sabbath, melting in the noon heat) substantially exceed what any natural substance does, indicating that natural parallels inform the description but do not explain the phenomenon.</p>",
    "15": "<p><b>When the people of Israel saw it, they said to one another, 'What is it (man hu')?' For they did not know what it was.</b> Man hu' (what is it?) = the etymological explanation for the name 'manna' (man); the word is probably related to the Egyptian 'mannu' or Semitic 'manna' (a secretion from plants or insects). The people name the substance by their ignorance of it — manna = the anonymous food, identified only by its divine origin and the question it provokes. Jesus's 'I am the bread of life' (John 6:35) takes up this etymology: he identifies himself as the answer to 'man hu' — the one who truly is the divine provision.</p>",
    "16": "<p><b>'This is what YHWH has commanded: Gather of it, each one of you, as much as he can eat. You shall each take an omer (omer) according to the number of the persons that each of you has in his tent.'</b> An omer (from the same root as 'sheaf' — the omer offering of Lev 23:10-14) = 1/10 of an ephah (approximately 2 liters). The per-person measuring system distributes the manna provision equitably: no household takes more than its proportional share. The omer measure will later be the unit for the firstfruits offering — the manna teaches Israel the economics of provision before they enter the agricultural land where the same principle will govern their harvest offering.</p>",
    "17": "<p><b>And the people of Israel did so. They gathered, some more, some less.</b> The brief notation of variety in gathering (who took more and who took less) sets up the miraculous equalization of v.18 — despite the difference in gathering, everyone had exactly what they needed. The distributive miracle (much-gathered = right amount; little-gathered = right amount) is a parable of divine provision that transcends human economy: in the wilderness economy of grace, the measure of effort does not determine the measure of provision.</p>",
    "18": "<p><b>But when they measured it with an omer, whoever gathered much had nothing left over, and whoever gathered little had no lack. Each of them gathered as much as he could eat.</b> Paul cites this verse in 2 Cor 8:15 to support the principle of economic leveling in the Jerusalem collection: 'as it is written, Whoever gathered much had nothing left over, and whoever gathered little had no lack.' The manna economy becomes Paul's model for Christian generosity — the surplus of some and the need of others are resolved by mutual sharing that produces equality (isotēs).</p>",
    "19": "<p><b>And Moses said to them, 'Let no one leave any of it over till morning.'</b> The command against hoarding manna overnight is the material form of daily dependence on YHWH. Hoarding food is the natural human response to scarcity anxiety — the command against it forces a daily faith-act: trusting that tomorrow's provision will come. The prohibition has exact structural parallels in ANE daily-ration systems (Egyptian and Mesopotamian administrative records show that daily rations were not transferable to the next day).</p>",
    "20": "<p><b>But they did not listen to Moses. Some left part of it till morning, and it bred worms (va'yaleer tolaim) and stank. And Moses was angry with them.</b> Tolaim = worms/maggots (the decomposition that natural food undergoes). The overnight spoilage is the natural physical consequence of trying to secure today's provision against tomorrow's uncertainty. The worms and stench are YHWH's enforced lesson in non-hoarding: you cannot save up grace for tomorrow. The manna-economy runs entirely on daily trust.</p>",
    "21": "<p><b>Morning by morning they gathered it, each as much as he could eat; but when the sun grew hot, it melted:</b> The morning gathering before the heat of the day is consistent with the Sinai climate — by mid-morning, temperatures rise sharply and anything left on the ground would indeed melt or dry up. The manna's time-sensitive character (gather before the sun gets hot) reinforces the daily urgency: provision is available but not indefinitely, requiring an active daily response.</p>",
    "22": "<p><b>On the sixth day they gathered twice as much bread, two omers each. And when all the leaders of the congregation came and told Moses:</b> The double-gathering on day six is the community's experiential discovery of the Sabbath pattern before they know what to call it. The leaders' report to Moses ('we gathered double today') is the occasion for Moses to explain what YHWH has already built into the manna-provision system. The Sabbath is discovered inductively through the provision before it is commanded deductively at Sinai — a pedagogical method consistent with ANE treaty ratification processes where covenant obligations are experienced before formally stated.</p>",
    "23": "<p><b>He said to them, 'This is what YHWH has commanded: Tomorrow is a day of solemn rest (shabbaton), a holy sabbath to YHWH.'</b> The first explicit use of shabbaton (intensive/solemn rest, from shavat = to cease) in the Bible. The word's first appearance names the coming reality that the manna-provision has been silently teaching. Shabbaton is a stronger form than simply shabbat; it occurs primarily in the Pentateuch for the most sacred rest occasions (Lev 16:31 = the Day of Atonement; Lev 23:24 = Rosh Hashana). The manna's sabbath-provision inaugurates the week as a theological unit of time before the formal Decalogue.</p>",
    "24": "<p><b>So they laid it aside till the morning, as Moses commanded them, and it did not stink, and there were no worms in it:</b> The Sabbath exception: the manna stored overnight on the sixth day does not spoil — no stench, no maggots. The miraculous preservation is the physical sign that the Sabbath rest is genuinely YHWH-commanded and YHWH-protected. The same food that rots when hoarded on other days stays fresh when stored for the Sabbath. The physical miracle validates the theological principle: Sabbath rest is not laziness but obedience.</p>",
    "25": "<p><b>Moses said, 'Eat it today, for today is a sabbath to YHWH; today you will not find it in the field.'</b> The command to eat the stored manna on the Sabbath confirms that the Sabbath is a day of provision and rest, not of fasting. The Sabbath is not characterized by lack but by sufficiency — what was gathered and stored on day six is enough for day seven. The provision is already there before the rest begins; the work of provision is complete before the rest is entered.</p>",
    "26": "<p><b>'Six days you shall gather it, but on the seventh day, which is a sabbath, there will be none.'</b> The absolute statement 'there will be none' (lo yihyeh bo) on the sabbath makes the sabbath manna-absence a structural feature of creation's weekly pattern, not a temporary exception. The seven-day week is here given its first explicit theological rationale through lived experience: six days of active provision, one day of divinely-prepared rest.</p>",
    "27": "<p><b>On the seventh day some of the people went out to gather, but they found nothing:</b> The test is immediate — some people disbelieve the announced sabbath-absence and go to gather. They find nothing. The Sabbath is not merely a divine suggestion; it is a feature of created reality. The disobedience is not punished directly (unlike later sabbath violations in Num 15:32-36) because the context is the initial introduction of the sabbath principle. The finding-nothing is itself the correction.</p>",
    "28": "<p><b>And YHWH said to Moses, 'How long will you refuse (me'antem) to keep my commandments and my laws?'</b> YHWH's rebuke of the manna-gatherers on the Sabbath — 'how long will you refuse?' — uses the same verb (me'aneyn = refuse, from ana' = to restrain/refuse) that Moses used to warn Pharaoh before the plagues. The irony: Israel in the wilderness refuses YHWH's commandments just as Pharaoh refused YHWH's demands. The wilderness generation mirrors Pharaoh's obduracy at smaller scale.</p>",
    "29": "<p><b>'See! YHWH has given you the sabbath; therefore on the sixth day he gives you bread for two days. Remain each of you in his place; let no one go out of his place on the seventh day.'</b> 'YHWH has given you the sabbath (natan lachem et-ha-shabbat)' — the Sabbath is a gift (natan), not merely a restriction. The double provision on day six is the material gift that makes the Sabbath rest possible. This verse is the only place in the Hebrew Bible where the Sabbath is explicitly described as a divine gift. The 'remain in your place' instruction anticipates later Sabbath legislation about travel limits.</p>",
    "30": "<p><b>So the people rested on the seventh day:</b> The brief notation of compliance — they rested (va'yishbetu) — uses the sabbath verb (shavat) for the people's action. The first Sabbath rest observed by Israel is not the seventh day of creation (which was YHWH's rest) but this seventh day in the wilderness of Sin. The people participate in the rest-pattern that creation embeds in time by obeying the manna's logic.</p>",
    "31": "<p><b>Now the house of Israel called its name manna (man). It was like coriander seed (gad), white, and the taste of it was like wafers made with honey:</b> The official naming of manna by Israel (beit Yisrael) confirms the folk etymology of v.15 (man hu' = what is it?). Gad = coriander seed (Coriandrum sativum); the comparison establishes the manna's size and shape (small, round, white). The taste like 'wafers in honey' (tzapichit bidvash) is the first biblical food description — the food of grace tastes sweet. Num 11:8 adds another flavor comparison (taste like cakes baked with oil), suggesting different preparations produced different taste experiences.</p>",
    "32": "<p><b>Moses said, 'This is what YHWH has commanded: Let an omer of it be kept throughout your generations, so that they may see the bread with which I fed you in the wilderness, when I brought you out of the land of Egypt.'</b> The preservation of an omer of manna as a memorial (l'dor dorot = throughout your generations) is the first object designated for permanent preservation in Israel's covenant memory. The manna-jar anticipates the ark of the covenant as the repository of covenant signs: tablets of the law, Aaron's rod, and the manna-jar (Heb 9:4) are the three objects preserved in the ark. Each represents a dimension of the wilderness covenant: law (tablets), priestly authority (Aaron's rod), and divine provision (manna).</p>",
    "33": "<p><b>And Moses said to Aaron, 'Take a jar (tzintznent) and put an omer of manna in it, and place it before YHWH to be kept throughout your generations.'</b> Tzintznenet = a jar/flask (a hapax legomenon — appearing only here in the Hebrew Bible; possibly a loanword from Egyptian or Canaanite). The jar is placed 'before YHWH' (lifnei YHWH) — in the context of the wilderness, this means before the testimony/covenant documents; later, Heb 9:4 specifies the jar was inside the ark. The preservation of the manna creates a tangible link between the wilderness generation and all future generations who would see the jar.</p>",
    "34": "<p><b>As YHWH commanded Moses, so Aaron placed it before the Testimony to be kept:</b> The Testimony (ha'edut) refers to the tablets of the covenant that will be given at Sinai — the manna-jar is placed before documents that don't yet exist, anticipating the tabernacle's construction. The narrative anticipates the completed sanctuary as the natural resting place for the manna memorial, retroactively locating Aaron's action in its ultimate institutional context.</p>",
    "35": "<p><b>The people of Israel ate the manna forty years (arba'im shanah), till they came to a habitable land. They ate the manna till they came to the border of the land of Canaan:</b> The forty years of manna is one of the most specific numerical claims in the Exodus-wilderness narrative. Forty years of daily miraculous provision is an extraordinary claim; the reference to it ending when Israel reached Canaan is confirmed in Josh 5:12 ('the manna ceased on the day after the Passover, when they ate of the produce of the land'). The continuity of provision from the wilderness of Sin through all forty years frames the manna as the signature of YHWH's covenant faithfulness for the entire wilderness period.</p>",
    "36": "<p><b>An omer is the tenth part of an ephah:</b> The final verse supplies a units-conversion note for readers unfamiliar with the omer measure. An ephah = approximately 20-22 liters; an omer = 1/10 of an ephah = approximately 2 liters. This is the only explicit conversion formula for the omer in the OT; Lev 23:13 and Num 28:5 use the omer but don't define it. The note is a scribal gloss explaining an older measure to later readers — evidence of the text's reception history within the Hebrew scribal tradition.</p>"
  },
  "17": {
    "1": "<p><b>All the congregation of the people of Israel moved on from the wilderness of Sin by stages, as YHWH commanded, and camped at Rephidim:</b> Rephidim (r'phidim = supports/rest-places?) is the penultimate station before Sinai in the wilderness itinerary. The exact location is debated but is generally placed in the western Sinai near the approach to Jebel Musa or Jebel Serbal — the mountain candidates for Sinai/Horeb. The wilderness itinerary of the Exodus is the earliest geographical text in the Hebrew Bible and has been the subject of archaeological and geographical study for over a century, though no consensus on exact routes has been reached.</p>",
    "2": "<p><b>Therefore the people quarreled (va'yarev) with Moses and said, 'Give us water to drink.' And Moses said to them, 'Why do you quarrel with me? Why do you test (t'nasun) YHWH?'</b> Rav (to quarrel/dispute) gives its name to the place Meribah (quarrel); nassah (to test) gives its name to the place Massah (testing). The two place-names (v.7) encode the theological verdict on the water-complaint — the place is named for the community's failure, not their experience. The distinction between crying to YHWH in genuine need and testing YHWH's provision is a fine but significant one; the wilderness complaint-cycle navigates this distinction throughout.</p>",
    "3": "<p><b>But the people thirsted there for water, and the people grumbled against Moses and said, 'Why did you bring us up out of Egypt, to kill us and our children and our livestock with thirst?'</b> The rhetoric of the complaint moves from the present crisis ('give us water') to a comprehensive accusation ('you brought us out to kill us'). The escalation from specific request to global accusation is the rhetorical pattern of panic-driven complaints throughout the Psalms' complaint genre (e.g., Ps 22). The inclusion of 'our children and our livestock' widens the complaint to cover the entire community's survival.</p>",
    "4": "<p><b>So Moses cried to YHWH, 'What shall I do with this people? They are almost ready to stone me (s'qol yisgal'uni).'</b> Moses's intercessory prayer here is a complaint to YHWH about the people rather than a petition on their behalf — a 'complaint within a complaint' structure. The threat of stoning (s'qal = to stone/pelt) was a legitimate form of community justice in ancient Israel (cf. Num 14:10 — the congregation threatens to stone Moses and Aaron at Kadesh-Barnea in a near-identical situation). The community's frustration is at a threshold where their loyalty to YHWH's appointed leader hangs by a thread.</p>",
    "5": "<p><b>And YHWH said to Moses, 'Pass on before the people, taking with you some of the elders of Israel, and take in your hand the staff with which you struck the Nile, and go.'</b> The elders of Israel serve as witnesses to the miracle — the same staff that struck the Nile (the instrument of the blood plague) now strikes the rock to produce water. The symbolic inversion is significant: the instrument of judgment on Egypt becomes the instrument of provision for Israel. The staff's dual function (plague-bringer + provision-giver) depends entirely on the direction in which YHWH commands it to be used.</p>",
    "6": "<p><b>'Behold, I will stand before you there on the rock at Horeb, and you shall strike the rock, and water shall come out of it, and the people will drink.' And Moses did so, in the sight of the elders of Israel:</b> YHWH standing on the rock at Horeb — the divine presence localized on the specific rock that will produce water. The identification of the location as Horeb (the alternative name for Sinai/the mountain of God) places this water miracle at the threshold of the covenant mountain. Paul identifies this rock with Christ in 1 Cor 10:4: 'they drank from the spiritual Rock that followed them, and the Rock was Christ.' The ANE tradition of a divine figure dwelling within or upon a rock (gods of the mountain) is inverted here: YHWH stands on the rock not to be worshipped there but to provide through it.</p>",
    "7": "<p><b>And he called the name of the place Massah (testing) and Meribah (quarreling), because of the quarreling of the people of Israel, and because they tested YHWH by saying, 'Is YHWH among us or not?'</b> The double place-naming encodes the theological verdict: Massah = test/temptation (from nassah), Meribah = contention/dispute (from rav/riv). The question 'Is YHWH among us or not?' (ha'yesh YHWH b'qirbeinu im-ayin) is the theological nadir of the water-crisis — the fundamental question of divine presence that the entire wilderness narrative is designed to answer. Ps 95:8-9 cites Massah/Meribah as the paradigmatic failure of faith that Israel must not repeat; Hebrews 3:7-11 extends the warning to the church. The question of divine presence (ha'yesh YHWH b'qirbeinu?) is answered throughout the tabernacle narrative with the emphatic: yes, he dwells among you.</p>",
    "8": "<p><b>Then Amalek came and fought with Israel at Rephidim:</b> The Amalekites are the first external military enemy Israel faces after the Exodus. In biblical genealogy, Amalek is the grandson of Esau through Eliphaz and his concubine Timna (Gen 36:12) — making the Amalekites distant relatives of Israel through the Esau line. Amalekite territory is attested in Egyptian and Akkadian sources as the region of the Negev and northern Sinai; they appear as a nomadic semi-desert people who controlled key water and trade routes. The attack at Rephidim — immediately after the water-from-rock miracle — may be connected to competition over water resources in the Sinai. Deut 25:17-18 specifies that Amalek 'cut off your tail' (attacked the stragglers at the rear of the marching column), a classic nomadic raiding tactic.</p>",
    "9": "<p><b>So Moses said to Joshua, 'Choose for us men, and go out and fight with Amalek. Tomorrow I will stand on the top of the hill with the staff of God in my hand.'</b> Joshua (Yehoshua = YHWH is salvation) makes his narrative debut here as military commander — his first appearance in the Exodus narrative since 24:13 (where he appears as Moses's attendant). The 'staff of God' (mateh ha-Elohim) is the staff of the plagues and the Red Sea crossing, now employed in warfare. Moses's position on the hilltop with the staff parallels the Egyptian pharaonic tradition of the king watching battle from an elevated position, but with a crucial difference: Moses is not directing the battle but interceding with the uplifted staff.</p>",
    "10": "<p><b>So Joshua did as Moses told him, and fought with Amalek, while Moses, Aaron, and Hur went up to the top of the hill:</b> Hur (mentioned here and in Exod 24:14 as Aaron's co-deputy over the people) is identified in later rabbinic tradition as Miriam's son or husband. He is mentioned twice in Exodus and then disappears from the narrative. In the Chronicler's genealogy (1 Chr 2:19-20), Hur is identified as the son of Caleb and Ephrath, and the grandfather of Bezalel (the tabernacle craftsman) — which would make him Moses's family connection to the tabernacle's construction team.</p>",
    "11": "<p><b>Whenever Moses held up his hand, Israel prevailed, and whenever he lowered his hand, Amalek prevailed:</b> The connection between Moses's uplifted hands and Israel's military fortunes is the theological principle of the passage: the battle belongs to YHWH and is mediated through Moses's intercession (uplifted hands = the classic prayer posture in the ancient Near East; cf. Ps 28:2, 63:4, 141:2; 1 Tim 2:8). The battle is not won by Israel's military superiority (Joshua was choosing men — implying a select force) but by sustained intercession from above. The hilltop position of Moses parallels Egyptian battle iconography where a deity or divine-king stands above the battle directing its outcome.</p>",
    "12": "<p><b>But Moses' hands grew weary, so they took a stone and put it under him, and he sat on it, while Aaron and Hur held up his hands, one on one side, and the other on the other side. So his hands were steady (emunah) until the going down of the sun:</b> Emunah = steadiness/faithfulness/firmness (the word translated 'faith/faithfulness' throughout the OT; cf. Hab 2:4 'the righteous shall live by emunah'). Moses's hands being emunah (steady/faithful) until sunset is the first occurrence of emunah as a narrative-action word rather than an abstract character quality. The community supporting the intercessor (Aaron and Hur holding Moses's arms) is the practical dimension of corporate prayer: sustained intercession requires the community's physical and spiritual support.</p>",
    "13": "<p><b>And Joshua overwhelmed (va'yachalosh) Amalek and his people with the sword's edge:</b> Chalash = to weaken/overwhelm/defeat (a rare verb in the military sense); the decisive defeat of Amalek 'at the mouth of the sword' (lefi-charev = at the sword's edge/lip). The victory is decisive but not total — Amalek is not annihilated here, only defeated. The incomplete defeat at Rephidim is the beginning of the long conflict between Israel and Amalek that will require further action (Deut 25:19; 1 Sam 15).</p>",
    "14": "<p><b>Then YHWH said to Moses, 'Write this as a memorial in a book and recite it in the ears of Joshua, that I will utterly blot out the memory of Amalek from under heaven.'</b> The command to write (k'tov zot zikaron b'sefer) is the first explicit writing command in the Exodus narrative after Moses's general writing of the Covenant Code (24:4). The sefer (book/scroll) as the medium for permanent covenant memory is established here: memory requires inscription. The command to 'recite it in the ears of Joshua' links the written memory to oral transmission — the written and oral Torah work together in covenant pedagogy. The eschatological blotting out (machoh emcheh et-zecher Amalek) is a permanent covenantal decree.</p>",
    "15": "<p><b>And Moses built an altar and called the name of it, YHWH is my Banner (YHWH nissi):</b> YHWH nissi = YHWH my banner/standard (nes = a pole or standard raised as a rallying point for troops in battle; cf. Isa 11:10,12; Num 21:8-9 — the bronze serpent on a 'nes'). The altar built at the battle-site names the theological principle learned: YHWH was Israel's true standard in the battle, raised high through Moses's intercession. The divine name as battle-standard anticipates the NT language of the cross as the nes/standard raised for all nations (John 12:32 — 'I, when I am lifted up, will draw all people to myself').</p>",
    "16": "<p><b>He said, 'A hand upon the throne of Yah (ki-yad al-kes Yah)! YHWH will have war with Amalek from generation to generation.'</b> The most difficult verse in the passage — 'ki-yad al-kes Yah' is grammatically ambiguous. Possible readings: 'Because a hand is against the throne of Yah' (Amalek attacks YHWH's throne by attacking Israel); or 'A hand on the standard/sign — Yah swears' (an oath formula). The LXX reads 'with a hidden hand.' The theological point regardless of the exact translation: the Amalekite attack on Israel is treated as an attack on YHWH's royal authority, making the conflict cosmic rather than merely tribal. The divine oath of permanent warfare 'from generation to generation (l'dor dor)' establishes Amalek as the paradigmatic enemy of YHWH's covenant people.</p>"
  },
  "18": {
    "1": "<p><b>Jethro, the priest of Midian (kohen Midyan), Moses's father-in-law, heard of all that God had done for Moses and for Israel his people, how YHWH had brought Israel out of Egypt:</b> Jethro (Yitro = his excellence?; also called Reuel in Exod 2:18 and Num 10:29; possibly the same person under different names, or the two names represent different traditions) is identified as kohen Midyan (priest of Midian) — a non-Israelite religious authority. The Midianites were a nomadic people of the northern Arabian/Sinai region, descendants of Abraham through Keturah (Gen 25:2). The Midianite connection to Israel through Moses (who spent 40 years with Jethro's family) created a unique cultural-religious relationship that appears at several critical moments (the burning bush; the judicial reorganization here; the later Midianite apostasy of Num 25 that makes the Midianite relationship complex).</p>",
    "2": "<p><b>Now Jethro, Moses's father-in-law, had taken Zipporah, Moses's wife, after he had sent her home:</b> The notation that Moses had 'sent away' (shillach = to send/divorce, the same technical term for divorce in Deut 24:1) Zipporah earlier is a gap in the narrative — there is no previous record of this sending-away. The most likely interpretation is that Moses sent Zipporah and the boys back to Midian at some point during the Egypt confrontations (possibly after the lodging-place circumcision incident of 4:24-26). This verse fills the gap retroactively, explaining why Jethro is now bringing Zipporah to Moses.</p>",
    "3": "<p><b>Along with her two sons. The name of the one was Gershom (for he said, 'I have been a sojourner in a foreign land'),</b> Gershom (ger + sham = sojourner there) is the son whose name encodes Moses's identity as a perpetual exile — he was a sojourner in Midian, just as Israel was a sojourner in Egypt. The naming of Gershom (Exod 2:22) is the first instance in the Exodus narrative of the ger (sojourner/alien) motif that will structure the ethical treatment of aliens in the Covenant Code (22:21, 23:9).</p>",
    "4": "<p><b>And the name of the other, Eliezer (for he said, 'The God of my father was my help, and delivered me from the sword of Pharaoh'):</b> Eliezer (El + ezer = my God is help) encodes the Exodus theology in a personal name — 'the God of my father' (Elohei avi) = the patriarchal God; 'delivered me from the sword of Pharaoh' = the specific rescue that preceded the Exodus (when Moses fled Pharaoh's sword after killing the Egyptian, Exod 2:15). Moses named his son after a personal deliverance that preceded the national deliverance; the personal and national Exodus stories are nested within each other.</p>",
    "5": "<p><b>Jethro, Moses's father-in-law, came with his sons and his wife to Moses in the wilderness where he was encamped at the mountain of God:</b> The mountain of God (har ha-Elohim) = Horeb/Sinai, the site of the burning bush (3:1) and the destination of the Exodus journey ('you will serve God on this mountain,' 3:12). The reunion of Moses with his family at the mountain of God is the fulfillment of the burning-bush promise — Moses is back at the mountain, but now at the head of a redeemed nation. The circle of the burning-bush narrative closes at Sinai.</p>",
    "6": "<p><b>And when he sent word to Moses, 'I, your father-in-law Jethro, am coming to you with your wife and her two sons with her,'</b> The formal announcement of Jethro's arrival follows ANE diplomatic protocol for important visits — a prior notification allowing the host to prepare a reception. The formality of the announcement contrasts with the intimacy of the family reunion in v.7; the diplomatic frame acknowledges that Jethro comes as a representative figure (priest of Midian) as well as a family member.</p>",
    "7": "<p><b>Moses went out to meet his father-in-law and bowed down (va'yishtachu) and kissed him. And they asked each other of their welfare and went into the tent:</b> Moses bowing (shachah = the full prostration-bow, the worship posture used for deity; also used for showing honor to humans) before his father-in-law reflects the honor culture of the ancient Near East in which a son-in-law showed deference to his wife's father. The mutual inquiry about welfare (va'yish'alu ish-l'ree'eihu l'shalom = they asked each other about peace/welfare) uses shalom as the greeting-word, connecting personal relational peace with the covenant peace that Israel has just secured through the Exodus.</p>",
    "8": "<p><b>Then Moses told his father-in-law all that YHWH had done to Pharaoh and to the Egyptians for Israel's sake, all the hardship that had come upon them in the way, and how YHWH had delivered them:</b> Moses's recounting of the Exodus story to Jethro is the first 'testimony' narration in the Exodus narrative — the eyewitness telling of YHWH's saving acts to an outsider. The structure (what YHWH did to Egypt + the hardship on the journey + YHWH's deliverance) is the proto-form of the Exodus creed that will be recited in Deut 6:20-25 and 26:5-9. The narrative function of telling the Exodus story to Jethro produces the first Gentile faith-response (v.11).</p>",
    "9": "<p><b>And Jethro rejoiced (vayyichdah) for all the good that YHWH had done to Israel, in that he had delivered them out of the hand of the Egyptians:</b> Chadah = to rejoice/be glad (a relatively rare verb; the cognate in Aramaic is cheda = joy). Jethro's joy for Israel's deliverance is the emotional prerequisite for his coming confession in v.11. The outsider who rejoices for YHWH's acts on behalf of his people is already moving toward faith — Jethro's joy is the precursor to his theological affirmation.</p>",
    "10": "<p><b>Jethro said, 'Blessed be YHWH (baruch YHWH), who has delivered you out of the hand of the Egyptians and out of the hand of Pharaoh and has delivered the people from under the hand of the Egyptians.'</b> The baruch YHWH formula (blessed be YHWH) is the standard Hebrew doxology, used by Melchizedek (Gen 14:20), Naomi (Ruth 2:20), and throughout the Psalms. Jethro the Midianite priest uses the covenant name YHWH (not El, not Elohim) — suggesting either that the Midianites already had knowledge of the YHWH name (the 'Kenite hypothesis' that Moses encountered YHWH-worship among the Midianites) or that Moses has been reporting YHWH's name to Jethro in the recounting of v.8.</p>",
    "11": "<p><b>'Now I know (ata yadati) that YHWH is greater than all gods (gadol YHWH mikol ha-elohim), for in this affair they dealt arrogantly with the people.'</b> Jethro's confession is the first Gentile doxology in the Exodus narrative and one of the earliest monotheistic (or henotheistic) declarations from a non-Israelite perspective. Ata yadati = 'now I know' — experiential knowledge (da'at) produced by hearing the Exodus testimony. Gadol YHWH mikol ha-elohim = 'YHWH is greater than all the gods' — the incomparability formula (cf. mi-kamokha ba'elim YHWH, 15:11) now made by an outsider. The 'Kenite hypothesis' (that Moses encountered YHWH-worship among the Midianites and that Jethro's priesthood was already YHWH-focused) is supported by this verse's confident use of the covenant name.</p>",
    "12": "<p><b>And Jethro, Moses's father-in-law, brought a burnt offering (olah) and sacrifices (zevachim) to God. And Aaron came with all the elders of Israel to eat bread with Moses's father-in-law before God:</b> Jethro officiates at a sacrifice before God — and Aaron (Israel's future high priest) and all the elders eat the covenant meal with Jethro. The shared meal 'before God' (lifnei ha-Elohim) is covenant-communion language; eating together before YHWH ratifies a relationship. The inclusion of Israel's entire leadership in Jethro's sacrificial meal is a remarkable act of Gentile-Israelite covenant fellowship that has no parallel elsewhere in the Pentateuch. Whether Jethro's priesthood was formally recognized as valid is debated, but the text clearly treats his sacrifice as acceptable to YHWH.</p>",
    "13": "<p><b>The next day Moses sat to judge the people, and the people stood around Moses from morning till evening:</b> Moses's role as sole judge for the entire Israelite community — 600,000 men plus dependents — is clearly unsustainable at any level of case complexity. The morning-to-evening session describes a genuinely exhausting system: every dispute in a community of perhaps 2-3 million people eventually reached Moses as the sole arbiter. Ancient Near Eastern legal systems typically involved multiple tiers of authority: local elders → city judges → royal courts. Moses's single-tier system is anomalous by ANE standards.</p>",
    "14": "<p><b>When Moses's father-in-law saw all that he was doing for the people, he said, 'What is this that you are doing for the people? Why do you sit alone, and all the people stand around you from morning till evening?'</b> Jethro observes the system and immediately diagnoses its unsustainability. His outsider perspective gives him a clarity that Moses, embedded in the system, lacks. The 'why do you sit alone?' (madua' ata yoshev l'vadecha) is the same 'alone' (levad) that appears in the creation narrative — 'it is not good for man to be alone' (Gen 2:18). The institutional aloneness of Moses is as unsustainable as the human aloneness that prompted creation of woman.</p>",
    "15": "<p><b>And Moses said to his father-in-law, 'Because the people come to me to inquire of God (lidrosh Elohim); when they have a dispute, they come to me and I decide between one person and another, and I make them know the statutes of God and his laws.'</b> Darash Elohim = to seek/inquire of God — the technical term for consulting an oracle or divine authority. Moses frames his role as more than judicial: he is the mediator of divine instruction (chuqqei ha-Elohim ve-torotav = the statutes of God and his laws). The judicial role is inseparable from the teaching role; deciding cases is simultaneously teaching the covenant law. This dual function (judge + teacher) is the model for the Levitical priesthood (Deut 33:10) and the prophetic office.</p>",
    "16": "<p><b>'When they have a dispute, they come to me and I decide between one person and another, and I make them know the statutes of God and his laws.'</b> The repeated description of Moses's dual function (deciding disputes + teaching statutes) emphasizes that judicial administration and covenant instruction are unified in his role. The separation of the judicial and teaching functions that Jethro will propose (delegates handle cases; Moses teaches law) preserves the unity of the original role by distributing its applications.</p>",
    "17": "<p><b>Moses's father-in-law said to him, 'What you are doing is not good.'</b> The blunt assessment lo-tov (not good) uses the same phrase as Gen 2:18 ('it is not good for man to be alone'). Jethro's 'not good' is institutional wisdom expressed in creation-theology language: the current structure is as contrary to human flourishing as the aloneness it took woman to resolve. The structural unsustainability is framed in terms of human good (tov), not merely organizational efficiency.</p>",
    "18": "<p><b>'You and the people with you will certainly wear out (naval tibbol), for the thing is too heavy (kaved) for you. You are not able to do it alone.'</b> Naval = to droop/be worn out/fade (the same root as naval = foolish — the name Nabal in 1 Sam 25 who 'wears out' those who deal with him); the doubled infinitive absolute (naval tibbol) is emphatic: you will surely be exhausted. Kaved = heavy (the same root as kavod/glory and the hardening of Pharaoh's heart) — the administrative burden is now 'heavy' on Moses in the same way Pharaoh's heart was 'heavy.' The organizational crisis mirrors the theological crisis of the plagues.</p>",
    "19": "<p><b>'Now obey my voice; I will give you advice, and God be with you! You shall represent the people before God and bring their cases to God.'</b> Jethro's counsel is explicitly submitted to divine oversight ('God be with you') — he is not imposing a secular administrative reorganization but proposing a structure within YHWH's framework. The proposal preserves Moses's irreplaceable role (representing the people before God, v'heyita ata la'am mul ha-Elohim = you being for the people opposite/before God) while distributing the derivative functions to others.</p>",
    "20": "<p><b>'And you shall warn them about the statutes and the laws, and make them know the way in which they must walk and what they must do.'</b> The four verbs of Moses's teaching function: warn (v'hizharta = from zahar, to shine/warn), make them know (v'hoda'ta = from yadah, to know), the way (ha-derech), and what to do (ha-ma'aseh). The teaching role is inseparable from the judicial role — Moses must continue to be the primary instructor of Torah even after he delegates the case-load. The Hebrew 'way' (derech) and 'deeds' (ma'aseh) encompass both ethical direction and practical application.</p>",
    "21": "<p><b>'Moreover, look for able men from all the people, men who fear God, who are trustworthy and hate a bribe, and place such men over the people as chiefs of thousands, hundreds, fifties, and tens.'</b> The four qualifications for judges: able (chayil = capable/valiant), God-fearing (yire'ei Elohim), trustworthy (anshei emet = men of truth/faithfulness), hating dishonest gain (son'ei vatza = hating unjust profit). The hierarchical structure (thousands, hundreds, fifties, tens) becomes the organizational framework for the Israelite military (Num 31:14), the early monarchy (2 Sam 18:1), and the New Testament church governance (the apostolic appointment of deacons echoes this structure, Acts 6:1-7). The Qumran community (Dead Sea Scrolls) also organized itself along this hierarchical model.</p>",
    "22": "<p><b>'And let them judge the people at all times. Every great matter they shall bring to you, but any small matter they shall decide themselves. So it will be easier for you, and they will bear the burden with you.'</b> The delegation principle: subsidiarity — decisions are made at the lowest competent level. Only 'great matters' (ha-davar ha-gadol) reach Moses; small matters (kol-ha-davar ha-qaton) are handled locally. This principle of subsidiarity (delegation to the most local competent authority) is embedded in Israelite law and governance from Sinai forward. It also ensures that Moses's authoritative rulings set precedents for the most complex and consequential cases, making his decisions constitutional in character.</p>",
    "23": "<p><b>'If you do this, God will direct you, you will be able to endure, and all this people also will go to their place in peace.'</b> The two outcomes of the reorganization: Moses's endurance (tuchal amod) and the people's peaceful return to their places (kol-ha'am ha-zeh al-m'qomo yavo b'shalom). The shalom of the people's daily life depends on a sustainable judicial system. The connection between institutional health and communal peace (shalom) — individual welfare requires structured, accessible justice — is a foundational principle of Israelite social theology.</p>",
    "24": "<p><b>So Moses listened to the voice of his father-in-law and did all that he had said:</b> Moses's willingness to receive counsel from a Gentile father-in-law and implement his organizational recommendations is a remarkable display of humility. The greatest leader in Israelite history accepts institutional wisdom from an outsider. Num 12:3 ('Moses was very humble, more than all people on the face of the earth') is illustrated here practically: the humble receive counsel even from unexpected sources.</p>",
    "25": "<p><b>Moses chose able men out of all Israel and made them heads over the people, chiefs of thousands, of hundreds, of fifties, and of tens:</b> The implementation of Jethro's proposal using the exact vocabulary of his recommendation (chayil = able, alafim/me'ot/chamishim/asarot = thousands/hundreds/fifties/tens) demonstrates full compliance. The judicial reorganization of Israel creates the first formal governmental structure of the Israelite community — the tribal elders and clan heads already existed, but this creates a formal judicial hierarchy with defined jurisdictions.</p>",
    "26": "<p><b>And they judged the people at all times. Any hard case (ha-davar ha-kashe) they brought to Moses, but any small matter they decided themselves:</b> The system in operation: the hard cases (kashe = difficult/hard — the same root as qashah in Pharaoh's stubbornness) escalate to Moses; the small cases are handled locally. The distribution of juridical difficulty mirrors the distribution of spiritual difficulty: the 'hard cases' that require direct access to YHWH's revealed instruction remain Moses's domain, while the 'small cases' that can be decided by applying known Torah principles are handled by the delegate judges.</p>",
    "27": "<p><b>Then Moses let his father-in-law depart, and he went away to his own country:</b> Jethro returns to Midian after his transformative visit — he came as the priest of Midian, confessed YHWH's supremacy, reorganized Israel's judiciary, and departed. The brevity of his departure (one verse) after his extensive contribution (the entire chapter) is characteristically Hebraic: the narrative does not dwell on farewells. Jethro disappears from the Exodus narrative after ch.18; his son Hobab appears in Num 10:29 as a potential guide for Israel in the wilderness, but whether Hobab was persuaded to stay is itself uncertain (Num 10:30-32).</p>"
  }
}

def main():
    existing = load_comm('mkt-context', 'exodus')
    merge_comm(existing, EXODUS_CONTEXT)
    save_comm('mkt-context', 'exodus', existing)
    print('Exodus 16-18 mkt-context commentary written.')

if __name__ == '__main__':
    main()
